// config/secrets.js
class SecretManager {
  constructor() {
    this.secrets = new Map();
  }

  // Validate secret format before use
  validateSecret(name, value) {
    const patterns = {
      'AWS_ACCESS_KEY_ID': /^AKIA[0-9A-Z]{16}$/,
      'STRIPE_SECRET_KEY': /^(sk_live|rk_live)_/,
      'DATABASE_URL': /^postgres:\/\//
    };

    const pattern = patterns[name];
    if (pattern && value && !pattern.test(value)) {
      console.warn(`Warning: ${name} does not match expected pattern`);
      return false;
    }
    return true;
  }

  get(name, required = false) {
    const value = process.env[name];

    if (!value) {
      if (required) {
        throw new Error(`Required secret ${name} is missing`);
      }
      return null;
    }

    // Validate secret format
    this.validateSecret(name, value);

    // Redact sensitive values in logs
    if (name.includes('SECRET') || name.includes('KEY') || name.includes('PASSWORD')) {
      const redacted = '***' + value.slice(-4);
      this.secrets.set(name, { value, redacted });
      return value;
    }

    this.secrets.set(name, { value });
    return value;
  }
}

module.exports = new SecretManager();
```

