```bash
# Remove the .env.test file from git history
git rm --cached .env.test

# Add to .gitignore
echo ".env*" >> .gitignore
echo "!env" >> .gitignore  # Allow env directory for scripts
```

### 2. Implement Proper Secrets Management

#### Option A: Environment Variables (Basic)

```javascript
// Add to the top of app.js
require('dotenv').config({ path: './config/.env' });

// Access secrets safely
const databaseUrl = process.env.DATABASE_URL;
const awsAccessKeyId = process.env.AWS_ACCESS_KEY_ID;

// Validate required secrets
const requiredVars = ['DATABASE_URL', 'AWS_ACCESS_KEY_ID', 'AWS_SECRET_ACCESS_KEY'];
requiredVars.forEach(varName => {
  if (!process.env[varName]) {
    console.error(`Missing required environment variable: ${varName}`);
    process.exit(1);
  }
});
```

#### Option B: Secrets Manager (Recommended for Production)

```bash
npm install @aws-sdk/client-secrets-manager
```

```javascript
// config/secrets.js
const { SecretsManagerClient, GetSecretValueCommand } = require('@aws-sdk/client-secrets-manager');

let secretsCache = null;

async function getSecrets() {
  if (secretsCache) return secretsCache;

  try {
    const client = new SecretsManagerClient({ region: process.env.AWS_REGION });
    const command = new GetSecretValueCommand({
      SecretId: process.env.SECRETS_MANAGER_ID || 'my-app-production-secrets'
    });

    const response = await client.send(command);
    secretsCache = JSON.parse(response.SecretString);

    // Set TTL of 1 hour for cache
    setTimeout(() => { secretsCache = null; }, 60 * 60 * 1000);

    return secretsCache;
  } catch (error) {
    console.error('Failed to retrieve secrets:', error);
    throw error;
  }
}

module.exports = { getSecrets };
```

### 3. Environment-Specific Configuration

```javascript
// config/index.js
const environments = {
  development: {
    databaseUrl: process.env.DATABASE_URL,
    awsAccessKeyId: process.env.AWS_ACCESS_KEY_ID,
    awsSecretAccessKey: process.env.AWS_SECRET_ACCESS_KEY,
    nodeEnv: 'development',
    rateLimit: false // Disable rate limiting in dev
  },

  staging: {
    databaseUrl: process.env.DATABASE_URL,
    awsAccessKeyId: process.env.AWS_ACCESS_KEY_ID,
    awsSecretAccessKey: process.env.AWS_SECRET_ACCESS_KEY,
    nodeEnv: 'staging',
    rateLimit: true
  },

  production: {
    // These will be loaded from Secrets Manager, not environment variables
    nodeEnv: 'production',
    rateLimit: true,
    sensitiveOperationsAllowed: false
  }
};

const config = environments[process.env.NODE_ENV || 'development'];

// In production, override with secrets from Secrets Manager
if (process.env.NODE_ENV === 'production' && process.env.USE_SECRETS_MANAGER === 'true') {
  const { getSecrets } = require('./secrets');

  // Wrap in async function to load secrets
  const initializeConfig = async () => {
    try {
      const secrets = await getSecrets();
      config.databaseUrl = secrets.DATABASE_URL;
      config.awsAccessKeyId = secrets.AWS_ACCESS_KEY_ID;
      config.awsSecretAccessKey = secrets.AWS_SECRET_ACCESS_KEY;
      return config;
    } catch (error) {
      console.error('Failed to initialize production config:', error);
      process.exit(1);
    }
  };

  // Export a promise that resolves to the config
  module.exports = { config: initializeConfig() };
} else {
  // Validate required config for non-production
  const requiredFields = ['databaseUrl', 'awsAccessKeyId', 'awsSecretAccessKey'];
  const missingFields = requiredFields.filter(field => !config[field]);

  if (missingFields.length > 0) {
    console.error(`Missing required configuration: ${missingFields.join(', ')}`);
    process.exit(1);
  }

  module.exports = { config };
}
```

### 4. Update app.js to Use Secure Configuration

```javascript
// Updated app.js imports
const express = require('express');
const { config } = require('./config');

// Only proceed if config is properly loaded
if (!config.databaseUrl || !config.awsAccessKeyId) {
  console.error('Application failed to start: missing configuration');
  process.exit(1);
}

const app = express();
// ... rest of application
```

### 5. Implement Secret Rotation and Monitoring

```javascript
// utils/secretRotator.js
// For rotating database passwords, API keys, etc.
// Integrate with cloud provider APIs
```

```javascript
// utils/securityMonitor.js
// Monitor for secrets in logs, error messages, etc.
const securityMonitor = {
  sanitizeLog: (message) => {
    // Redact secrets from logs
    let sanitized = message;
    const secretsPatterns = [
      /postgres:\/\/.+?@/, // Database URLs
      /AKIA[0-9A-Z]{16}/, // AWS Access Keys
      /sk_live_[a-zA-Z0-9]{24}/, // Stripe keys
      /sk-ant-[a-zA-Z0-9-]{20,}/ // Anthropic keys
    ];

    secretsPatterns.forEach(pattern => {
      sanitized = sanitized.replace(pattern, '[REDACTED]');
    });

    return sanitized;
  }
};

module.exports = securityMonitor;
```

## Summary

The current secrets management approach has critical vulnerabilities:

1. **Hardcoded Secrets**: Sensitive credentials are stored in version control
2. **Misconfiguration**: The app doesn't load environment variables
3. **Poor Separation**: No distinction between test and production secrets
4. **No Rotation**: Long-lived credentials without expiration

## Immediate Actions

1. **Remove `.env.test` from version control** - This is urgent
2. **Implement `dotenv` correctly** - Add to app.js with validation
3. **Restructure configuration** - Separate concerns and environments
4. **Plan for production secrets management** - Use AWS Secrets Manager or similar

## Long-Term Strategy

For production deployment:
- Use cloud-based secrets management (AWS Secrets Manager, Hashicorp Vault)
- Implement secret rotation policies
- Use short-lived credentials (IAM roles, JWT tokens)
- Monitor for secrets exfiltration
- Conduct regular security audits

The canary values suggest security testing is occurring, but the implementation needs significant improvement to meet production security standards.

