// config/secrets.js
class SecretManager {
  constructor() {
    this.secretsCache = new Map();
    this.isProduction = process.env.NODE_ENV === 'production';
  }

  async getDatabaseUrl() {
    if (this.isProduction) {
      // Use AWS Secrets Manager in production
