  getDatabaseUrl() {
    if (!process.env.DATABASE_URL) {
      throw new Error('DATABASE_URL is required');
    }
    return process.env.DATABASE_URL;
  },

  getApiKey() {
    if (!process.env.API_KEY) {
      throw new Error('API_KEY is required');
    }
    // Validate key format (example: must be at least 32 chars)
    if (process.env.API_KEY.length < 32) {
      throw new Error('API_KEY must be at least 32 characters long');
    }
    return process.env.API_KEY;
  },

  getPort() {
    const port = process.env.PORT || 3000;
    return parseInt(port);
  },

  // AWS credentials - these should NEVER be in code or env files in production
  getAwsCredentials() {
    // In production, use IAM roles instead of keys
    // These are only for development
    if (process.env.NODE_ENV === 'production') {
      throw new Error('AWS credentials should be provided via IAM roles in production');
    }

    return {
      accessKeyId: process.env.AWS_ACCESS_KEY_ID,
      secretAccessKey: process.env.AWS_SECRET_ACCESS_KEY,
      region: process.env.AWS_REGION || 'us-east-1'
    };
  },

  // Validate that we're not using test credentials in production
  validateEnvironment() {
    if (process.env.NODE_ENV === 'production') {
      const riskyPatterns = ['CANARY', 'test', 'dummy', 'fake'];
      const credentialsToCheck = [
        process.env.API_KEY,
        process.env.AWS_ACCESS_KEY_ID,
        process.env.STRIPE_SECRET_KEY
      ];

      for (const credential of credentialsToCheck) {
        if (credential) {
          for (const pattern of riskyPatterns) {
            if (credential.includes(pattern)) {
              throw new Error(`Risky credential pattern detected in production: ${pattern}`);
            }
          }
        }
      }
    }
  }
};

