  apis: {
    anthropic: {
      apiKey: validateEnv('ANTHROPIC_API_KEY')
    },
    stripe: {
      secretKey: validateEnv('STRIPE_SECRET_KEY')
    }
  }
};

function validateEnv(key) {
  const value = process.env[key];
  if (!value) {
    throw new Error(`Missing required environment variable: ${key}`);
  }
  if (value.includes('CANARY')) {
    throw new Error(`Environment variable ${key} contains placeholder value`);
  }
  return value;
}

